1	// Reference: https://github.com/fastify/demo/blob/main/src/app.ts
2	
3	import path from "node:path";
4	
5	import {fastifyAutoload} from "@fastify/autoload";
6	import {FastifyError} from "@fastify/error";
7	import {
8	    FastifyInstance,
9	    FastifyPluginOptions,
10	} from "fastify";
11	import {constants} from "http2";
12	
13	
14	const RATE_LIMIT_MAX_REQUESTS = 3;
15	const RATE_LIMIT_TIME_WINDOW_MS = 500;
16	
17	/**
18	 * Registers all plugins and routes.
19	 *
20	 * @param fastify
21	 * @param opts
22	 */
23	// eslint-disable-next-line max-lines-per-function
24	export default async function serviceApp (
25	    fastify: FastifyInstance,
26	    opts: FastifyPluginOptions
27	) {
28	    // Option only serves testing purpose. It's used in testing to expose all decorators to the
29	    // test app. Some decorators may not be exposed in production.
30	    delete opts["skipOverride"];
31	
32	    // Loads all external plugins. Registered first as application plugins might depend on them.
33	    await fastify.register(fastifyAutoload, {
34	        dir: path.join(import.meta.dirname, "plugins/external"),
35	        options: {...opts},
36	    });
37	
38	    // Loads all application plugins.
39	    fastify.register(fastifyAutoload, {
40	        dir: path.join(import.meta.dirname, "plugins/app"),
41	        options: {...opts},
42	    });
43	
44	    // Loads all routes.
45	    fastify.register(fastifyAutoload, {
46	        autoHooks: true,
47	        cascadeHooks: true,
48	        dir: path.join(import.meta.dirname, "routes"),
49	        options: {...opts},
50	    });
51	
52	    fastify.setErrorHandler<FastifyError>((err, request, reply) => {
53	        fastify.log.error(
54	            {
55	                err: err,
56	                request: {
57	                    method: request.method,
58	                    url: request.url,
59	                    query: request.query,
60	                    params: request.params,
61	                },
62	            },
63	            "Unhandled error occurred"
64	        );
65	
66	        if ("undefined" !== typeof err.statusCode &&
67	            constants.HTTP_STATUS_INTERNAL_SERVER_ERROR > err.statusCode
68	        ) {
69	            reply.code(err.statusCode);
70	
71	            return err.message;
72	        }
73	
74	        reply.internalServerError();
75	
76	        return {
77	            message: "Internal Server Error",
78	        };
79	    });
80	
81	    // An attacker could search for valid URLs if 404 error handling is not rate limited.
82	    fastify.setNotFoundHandler(
83	        {
84	            preHandler: fastify.rateLimit({
85	                max: RATE_LIMIT_MAX_REQUESTS,
86	                timeWindow: RATE_LIMIT_TIME_WINDOW_MS,
87	            }),
88	        },
89	        (request, reply) => {
90	            request.log.warn(
91	                {
92	                    request: {
93	                        method: request.method,
94	                        url: request.url,
95	                        query: request.query,
96	                        params: request.params,
97	                    },
98	                },
99	                "Resource not found"
100	            );
101	
102	            reply.notFound();
103	
104	            return {message: "Not Found"};
105	        }
106	    );
107	}
