3	import closeWithGrace from "close-with-grace";
4	import fastify from "fastify";
5	import fp from "fastify-plugin";
6	
7	import serviceApp from "./app.js";
8	
9	
10	const DEFAULT_FASTIFY_CLOSE_GRACE_DELAY = 500;
11	
12	/**
13	 * Generates logger configuration options based on the environment.
14	 *
15	 * @return Logger options for Fastify.
16	 */
17	const getLoggerOptions = () => {
18	    // Only if the program is running in an interactive terminal.
19	    if (process.stdout.isTTY) {
20	        return {
21	            level: process.env["LOG_LEVEL"] ?? "info",
22	            transport: {
23	                target: "pino-pretty",
24	                options: {
25	                    ignore: "pid,hostname",
26	                },
27	            },
28	        };
29	    }
30	
31	    return {level: process.env["LOG_LEVEL"] ?? "info"};
32	};
33	
34	const app = fastify({
35	    logger: getLoggerOptions(),
36	});
37	
38	/**
39	 * Initialize the Fastify server.
40	 *
41	 * @return
42	 */
43	const init = async (): Promise<void> => {
44	    // fp must be used to override default error handler.
45	    app.register(fp(serviceApp));
46	
47	    closeWithGrace(
48	        {delay: DEFAULT_FASTIFY_CLOSE_GRACE_DELAY},
49	        async ({err}) => {
50	            if (err) {
51	                app.log.error(err);
52	            }
53	
54	            await app.close();
55	        }
56	    );
57	
58	    await app.ready();
59	
60	    try {
61	        await app.listen({host: app.config.HOST, port: app.config.PORT});
62	    } catch (err) {
63	        app.log.error(err);
64	        process.exit(1);
65	    }
66	};
67	
68	await init();
