1	import {Hono} from "hono";
2	
3	import {dashboardRoutes} from "./hono-routes/dashboards.js";
4	import {datasourceRoutes} from "./hono-routes/datasource.js";
5	
6	
7	const BYTES_PER_KB = 1024;
8	const BYTES_PER_MB = BYTES_PER_KB * BYTES_PER_KB;
9	const MAX_BODY_SIZE = BYTES_PER_MB;
10	const MAX_RESPONSE_SIZE = 50 * BYTES_PER_MB;
11	const CLP_HEADER_PREFIX = "x-clp-";
12	const GATEWAY_HEADER = "x-clp-gateway";
13	const HTTP_FORBIDDEN = 403;
14	const HTTP_RATE_LIMITED = 429;
15	const HTTP_PAYLOAD_TOO_LARGE = 413;
16	const HTTP_REQUEST_TIMEOUT = 408;
17	const RATE_LIMIT_WINDOW_MS = 60_000;
18	const RATE_LIMIT_MAX_HITS = 100;
19	const SERVER_REQUEST_TIMEOUT_MS = 120_000;
20	const MS_PER_SECOND = 1000;
21	
22	type Role = "viewer" | "editor" | "admin";
23	
24	const ROLE_HIERARCHY: Record<Role, number> = {admin: 2, editor: 1, viewer: 0};
25	
26	const WRITE_METHODS = new Set(["POST",
27	    "PUT",
28	    "PATCH",
29	    "DELETE"]);
30	
31	/**
32	 *
33	 */
34	function isProduction (): boolean {
35	    // eslint-disable-next-line dot-notation
36	    return "production" === process.env["NODE_ENV"];
37	}
38	
39	/**
40	 *
41	 * @param c
42	 * @param c.req
43	 * @param c.req.header
44	 */
45	function getRole (c: {req: {header: (name: string) => string | undefined}}): Role {
46	    const roleHeader = c.req.header("x-clp-role")?.toLowerCase();
47	    if (roleHeader && roleHeader in ROLE_HIERARCHY) {
48	        return roleHeader as Role;
49	    }
50	
51	    return "viewer";
52	}
53	
54	/**
55	 *
56	 * @param userRole
57	 * @param requiredRole
58	 */
59	function hasRole (userRole: Role, requiredRole: Role): boolean {
60	    return ROLE_HIERARCHY[userRole] >= ROLE_HIERARCHY[requiredRole];
61	}
62	
63	/** Simple in-memory rate limiter */
64	class RateLimiter {
65	    private hits = new Map<string, {count: number; resetAt: number}>();
66	
67	    private maxHits: number;
68	
69	    private windowMs: number;
70	
71	    constructor (maxHits: number, windowMs: number) {
72	        this.maxHits = maxHits;
73	        this.windowMs = windowMs;
74	    }
75	
76	    check (ip: string): {allowed: boolean; remaining: number; resetAt: number} {
77	        const now = Date.now();
78	        let entry = this.hits.get(ip);
79	        if (!entry || now >= entry.resetAt) {
80	            entry = {count: 0, resetAt: now + this.windowMs};
81	            this.hits.set(ip, entry);
82	        }
83	        entry.count++;
84	        const allowed = entry.count <= this.maxHits;
85	        return {allowed: allowed, remaining: Math.max(0, this.maxHits - entry.count), resetAt: entry.resetAt};
86	    }
87	}
88	
89	const dashboardLimiter = new RateLimiter(RATE_LIMIT_MAX_HITS, RATE_LIMIT_WINDOW_MS);
90	
91	/**
92	 * Hono app for dashboard + datasource routes.
93	 * Must use chained route definitions for AppType inference.
94	 */
95	export const honoApp = new Hono()
96	
97	// NFR-12: Reject X-CLP-* headers from untrusted sources (spoofing prevention)
98	// In production: without a gateway, any x-clp-* header is spoofed → reject.
99	// With a gateway, only x-clp-role is trusted; other x-clp-* headers are suspicious → reject.
100	// Gateway marker is preserved here for NFR-11 to check, then deleted in NFR-11 after RBAC.
101	    .use("/api/*", async (c, next) => {
102	        if (isProduction()) {
103	            const hasGatewayHeader = Boolean(c.req.header(GATEWAY_HEADER));
104	            for (const [key] of c.req.raw.headers.entries()) {
105	                if (key.startsWith(CLP_HEADER_PREFIX) && key !== GATEWAY_HEADER) {
106	                    if (!hasGatewayHeader) {
107	                        c.status(HTTP_FORBIDDEN);
108	
109	                        return c.json({error: `Rejected spoofed header: ${key}`});
110	                    } else if (key !== "x-clp-role") {
111	                        // Gateway present but non-role x-clp-* header is suspicious
112	                        c.status(HTTP_FORBIDDEN);
113	
114	                        return c.json({error: `Rejected spoofed header: ${key}`});
115	                    }
116	                }
117	            }
118	        }
119	
120	        return next();
121	    })
122	
123	// NFR-11: RBAC enforcement in production mode when a gateway is present.
124	// The gateway is responsible for setting x-clp-role based on authenticated user
125	// permissions. Without a gateway, requests are direct from trusted clients and
126	// all operations are permitted.
127	    .use("/api/*", async (c, next) => {
128	        if (!isProduction()) {
129	            return next();
130	        }
131	        const hasGateway = Boolean(c.req.header(GATEWAY_HEADER));
132	        if (!hasGateway) {
133	            return next();
134	        }
135	        const role = getRole(c);
136	        const {method} = c.req;
137	
138	        // Write operations require editor role; read operations allow viewer
139	        if (WRITE_METHODS.has(method) && !hasRole(role, "editor")) {
140	            c.status(HTTP_FORBIDDEN);
141	
142	            return c.json({error: "Insufficient permissions for this operation"});
143	        }
144	
145	        // Strip gateway marker so downstream can't re-use it
146	        c.req.raw.headers.delete(GATEWAY_HEADER);
147	
148	        return next();
149	    })
150	    .use("/api/dashboards/*", async (c, next) => {
151	        const ip = c.req.raw.headers.get("x-forwarded-for")?.split(",")[0]?.trim() ?? c.req.raw.headers.get("x-real-ip") ?? "unknown";
152	        const {allowed, remaining, resetAt} = dashboardLimiter.check(ip);
153	        c.header("X-RateLimit-Remaining", String(remaining));
154	        c.header("X-RateLimit-Reset", String(Math.ceil(resetAt / MS_PER_SECOND)));
155	        if (!allowed) {
156	            c.status(HTTP_RATE_LIMITED);
157	
158	            return c.json({error: "Rate limit exceeded. Try again later."});
159	        }
160	
161	        return next();
162	    })
163	    .use("/api/dashboards/*", async (c, next) => {
164	        const contentLength = c.req.raw.headers.get("content-length");
165	        if (contentLength && parseInt(contentLength, 10) > MAX_BODY_SIZE) {
166	            c.status(HTTP_PAYLOAD_TOO_LARGE);
167	
168	            return c.json({error: "Request body exceeds 1MB limit"});
169	        }
170	
171	        return next();
172	    })
173	
174	// NFR: Request timeout — prevents long-running queries from blocking the server
175	    .use("/api/*", async (c, next) => {
176	        const controller = new AbortController();
177	        const timeout = setTimeout(() => {
178	            controller.abort();
179	        }, SERVER_REQUEST_TIMEOUT_MS);
180	
181	        c.req.raw.signal.addEventListener("abort", () => {
182	            controller.abort();
183	        });
184	
185	        try {
186	            await Promise.race([
187	                next(),
188	                new Promise((resolve) => {
189	                    controller.signal.addEventListener("abort", () => {
190	                        resolve(null);
191	                    });
192	                }),
193	            ]);
194	        } finally {
195	            clearTimeout(timeout);
196	        }
197	
198	        if (controller.signal.aborted && !c.req.raw.signal.aborted) {
199	            c.status(HTTP_REQUEST_TIMEOUT);
200	
201	            return c.json({error: "Request timed out"});
202	        }
203	
204	        return c.body(null);
205	    })
206	// NFR: Response payload size limit — prevents sending arbitrarily large JSON responses
207	    .use("/api/*", async (c, next) => {
208	        await next();
209	        const contentType = c.res.headers.get("content-type") ?? "";
210	        if (contentType.includes("application/json")) {
211	            const body = c.res.clone().body;
212	            if (body) {
213	                const reader = body.getReader();
214	                let totalBytes = 0;
215	                // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
216	                while (true) {
217	                    const {done, value} = await reader.read();
218	                    if (done) break;
219	                    totalBytes += value.length;
220	                    if (totalBytes > MAX_RESPONSE_SIZE) {
221	                        reader.cancel().catch(() => {});
222	                        c.res = c.json({error: `Response payload exceeds ${MAX_RESPONSE_SIZE / BYTES_PER_MB}MB limit`}, 413);
223	                        return;
224	                    }
225	                }
226	            }
227	        }
228	    })
229	    .route("/api/dashboards", dashboardRoutes)
230	    .route("/api/datasource", datasourceRoutes);
231	
232	/** Export AppType for client-side typed RPC via hc<AppType>() */
233	export type AppType = typeof honoApp;
234	

