1	import {tbValidator} from "@hono/typebox-validator";
2	import type {TSchema} from "@sinclair/typebox";
3	import {CreateDatasourceSchema, type CreateDatasourceRequest, UpdateDatasourceSchema, type UpdateDatasourceRequest} from "@webui/common/dashboard/schemas";
4	import type {DatasourceInstance} from "@webui/common/dashboard/types";
5	import {getCircuitBreaker} from "@webui/datasource/circuit-breaker";
6	import {executeInfinityQuery} from "@webui/datasource/infinity";
7	import {
8	    getApplicableRowLimit,
9	    injectLimit,
10	    rowsToDataFrame,
11	    validateSqlSafety,
12	} from "@webui/datasource/mysql";
13	import {QUERY_TIMEOUTS} from "@webui/datasource/types";
14	import {Hono} from "hono";
15	import {streamSSE} from "hono/streaming";
16	import {nanoid} from "nanoid";
17	
18	import {executeClpQueryStreaming} from "./clp-query-executor.js";
19	import type {DatasourceStorage} from "../storage/datasource-storage.js";
20	import {InMemoryDatasourceStorage} from "../storage/datasource-storage.js";
21	import {toMySQLDatetime} from "../storage/datetime-utils.js";
22	import settings from "../../settings.json" with {type: "json"};
23	
24	
25	/** Datasource storage (swappable: in-memory for dev, MySQL for production) */
26	let dsStorage: DatasourceStorage = new InMemoryDatasourceStorage();
27	
28	/**
29	 *
30	 * @param s
31	 */
32	export function setDatasourceStorage (s: DatasourceStorage): void {
33	    dsStorage = s;
34	}
35	
36	/** Allowed hosts for Infinity datasource (configurable via env) */
37	// eslint-disable-next-line dot-notation
38	const infinityAllowedHosts: string[] = (process.env["INFINITY_ALLOWED_HOSTS"] ?? "").split(",").filter(Boolean);
39	
40	/** Active query abort controllers for cancellation */
41	const activeQueries = new Map<string, AbortController>();
42	
43	/** Datasource routes (Hono, chained for RPC type inference) */
44	export const datasourceRoutes = new Hono()
45	    .get("/", async (c) => {
46	        const datasources = await dsStorage.list();
47	        return c.json(datasources);
48	    })
49	    .post("/", tbValidator("json", CreateDatasourceSchema as unknown as TSchema), async (c) => {
50	        const body = c.req.valid("json") as CreateDatasourceRequest;
51	        const now = toMySQLDatetime();
52	        const datasource: DatasourceInstance = {
53	            id: nanoid(21),
54	            uid: body.uid ?? nanoid(10),
55	            name: body.name,
56	            type: body.type,
57	            config: body.config,
58	            isDefault: body.isDefault ?? false,
59	            createdAt: now,
60	            updatedAt: now,
61	        };
62	
63	        await dsStorage.create(datasource);
64	
65	        return c.json(datasource, 201);
66	    })
67	    .get("/:uid", async (c) => {
68	        const uid = c.req.param("uid");
69	        const datasource = await dsStorage.get(uid);
70	        if (!datasource) {
71	            return c.json({error: "Datasource not found"}, 404);
72	        }
73	
74	        return c.json(datasource);
75	    })
76	    .put("/:uid", tbValidator("json", UpdateDatasourceSchema as unknown as TSchema), async (c) => {
77	        const uid = c.req.param("uid");
78	        const body = c.req.valid("json") as UpdateDatasourceRequest;
79	        const updated = await dsStorage.update(uid, body);
80	        if (!updated) {
81	            return c.json({error: "Datasource not found"}, 404);
82	        }
83	
84	        return c.json(updated);
85	    })
86	    .delete("/:uid", async (c) => {
87	        const uid = c.req.param("uid");
88	        const deleted = await dsStorage.delete(uid);
89	        if (!deleted) {
90	            return c.json({error: "Datasource not found"}, 404);
91	        }
92	
93	        return c.json({message: "Datasource deleted"}, 200);
94	    })
95	    .post("/:type/query", async (c) => {
96	        const dsType = c.req.param("type");
97	        const body = await c.req.json();
98	        const requestId = body.requestId ?? nanoid(10);
99	
100	        // Cancel any previous query with the same requestId
