406	/**
407	 *
408	 * @param sql
409	 * @param timeoutMs
410	 * @param params
411	 */
412	async function executeMySQLQuery (
413	    sql: string,
414	    timeoutMs: number = QUERY_TIMEOUTS.MYSQL_QUERY_TIMEOUT_MS,
415	    params?: unknown[],
416	): Promise<Record<string, unknown>[]> {
417	    // In production, this uses the @fastify/mysql connection
418	    // For now, use mysql2 directly with env-based config
419	    const {SqlDbHost: host, SqlDbPort: port, SqlDbName: database} = settings;
420	    // eslint-disable-next-line dot-notation
421	    const user = process.env["CLP_DB_USER"] ?? "clp-user";
422	    // eslint-disable-next-line dot-notation
423	    const password = process.env["CLP_DB_PASS"] ?? "";
424	
425	    const mysql = await import("mysql2/promise");
426	    const connection = await mysql.createConnection({host, port, user, password, database});
427	
428	    const timeoutId = setTimeout(() => {
429	        connection.destroy();
430	    }, timeoutMs);
431	
432	    try {
433	    // Enforce read-only mode at connection level
434	        await connection.query("SET TRANSACTION READ ONLY");
435	        await connection.query("START TRANSACTION");
436	        const [rows] = params ?
437	            await connection.query(sql, params) :
438	            await connection.query(sql);
439	        await connection.query("COMMIT");
440	
441	        return Array.isArray(rows) ?
442	            rows as Record<string, unknown>[] :
443	            [];
444	    } catch (error) {
445	        try {
446	            await connection.query("ROLLBACK");
447	        } catch {/* ignore rollback error */}
448	        if (error instanceof Error && error.message.includes("Connection destroyed")) {
449	            throw new Error(`MySQL query timed out after ${timeoutMs}ms`);
450	        }
451	        throw error;
452	    } finally {
453	        clearTimeout(timeoutId);
454	        connection.destroy();
455	    }
456	}
