594	    };
595	
596	    // eslint-disable-next-line dot-notation
597	    if (q["url"] !== undefined) {
598	        // eslint-disable-next-line dot-notation
599	        result["url"] = q["url"];
600	    }
601	    // eslint-disable-next-line dot-notation
602	    if (q["data"] !== undefined) {
603	        // eslint-disable-next-line dot-notation
604	        result["data"] = q["data"];
605	    }
606	    // eslint-disable-next-line dot-notation
607	    if (q["rootSelector"] !== undefined) {
608	        // eslint-disable-next-line dot-notation
609	        result["rootSelector"] = q["rootSelector"];
610	    }
611	    // eslint-disable-next-line dot-notation
612	    if (q["urlOptions"] !== undefined) {
613	        // eslint-disable-next-line dot-notation
614	        result["urlOptions"] = q["urlOptions"];
615	    }
616	    // eslint-disable-next-line dot-notation
617	    if (q["columns"] !== undefined) {
618	        // eslint-disable-next-line dot-notation
619	        result["columns"] = q["columns"];
620	    }
621	    // eslint-disable-next-line dot-notation
622	    if (q["pagination"] !== undefined) {
623	        // eslint-disable-next-line dot-notation
624	        result["pagination"] = q["pagination"];
625	    }
626	
627	    return result as unknown as Parameters<typeof executeInfinityQuery>[0];
628	}
