19	const plugin: FastifyPluginAsyncTypebox = async (fastify) => {
20	    const {StreamFileManager} = fastify;
21	
22	    fastify.post(
23	        "/extract",
24	        {
25	            schema: {
26	                body: StreamFileExtractionSchema as never,
27	                response: {
28	                    [constants.HTTP_STATUS_OK]: StreamFileMetadataSchema,
29	                    [constants.HTTP_STATUS_BAD_REQUEST]: ErrorSchema,
30	                },
31	                tags: ["Stream Files"],
32	            },
33	        },
34	        async (request, reply) => {
35	            const {dataset, extractJobType, logEventIdx, streamId} = request.body as StreamFileExtraction;
36	
37	            if (false === EXTRACT_JOB_TYPES.has(extractJobType)) {
38	                return reply.badRequest(`Invalid extractJobType="${extractJobType}".`);
39	            }
40	
41	            let streamMetadata = await StreamFileManager.getExtractedStreamFileMetadata(
42	                streamId,
43	                logEventIdx
44	            );
45	
46	            if (null === streamMetadata) {
47	                const extractResult = await StreamFileManager.submitAndWaitForExtractStreamJob({
48	                    dataset: dataset,
49	                    jobType: extractJobType,
50	                    logEventIdx: logEventIdx,
51	                    streamId: streamId,
52	                    targetUncompressedSize: settings.StreamTargetUncompressedSize,
53	                });
54	
55	                if (null === extractResult) {
56	                    return reply.badRequest(
57	                        `Unable to extract stream with streamId=${streamId} at ` +
58	                        `logEventIdx=${logEventIdx}`
59	                    );
60	                }
61	
62	                streamMetadata = await StreamFileManager.getExtractedStreamFileMetadata(
63	                    streamId,
64	                    logEventIdx
65	                );
66	
67	                if (null === streamMetadata) {
68	                    return reply.badRequest(
69	                        `Unable to extract stream with streamId=${streamId} at ` +
70	                        `logEventIdx=${logEventIdx}`
