75	            if (fastify.hasDecorator("StreamFilesS3Manager") &&
76	                "undefined" !== typeof fastify.StreamFilesS3Manager) {
77	                streamMetadata.path = await fastify.StreamFilesS3Manager.getPreSignedUrl(
78	                    `s3://${settings.StreamFilesS3PathPrefix}${streamMetadata.path}`
79	                );
80	            } else {
81	                streamMetadata.path = `/streams/${streamMetadata.path}`;
