13	const POLL_BATCH_SIZE = 100;
14	const SEARCH_MAX_NUM_RESULTS = 1000;
15	
16	/** MongoDB document type (avoid DOM Document collision) */
17	type MongoDoc = Record<string, unknown>;
18	
19	interface ClpQueryOptions {
20	  queryString: string;
21	  datasets: string[];
22	  ignoreCase: boolean;
23	  timeRange: {from: number; to: number};
24	  queryType: "search" | "aggregate";
25	  refId: string;
26	  timeRangeBucketSizeMillis?: number;
27	}
28	
29	export interface ClpStreamCallbacks {
30	  onPartial: (result: {data: unknown[]}) => Promise<void>;
31	  signal?: AbortSignal;
32	}
33	
34	/**
35	 * Submits CLP search/aggregation jobs and streams partial DataFrames as results arrive.
36	 *
37	 * The flow:
38	 * 1. Submit search + aggregation jobs via QueryJobDbManager
39	 * 2. Create MongoDB collections for results
40	 * 3. Insert metadata document tracking job status
41	 * 4. Poll MongoDB incrementally for new results, emitting partial DataFrames
42	 * 5. Detect job completion via metadata document's lastSignal
43	 * 6. Cancel jobs and clean up on abort
44	 *
45	 * @param opts
46	 * @param callbacks
47	 */
48	export async function executeClpQueryStreaming(
49	  opts: ClpQueryOptions,
50	  callbacks: ClpStreamCallbacks,
51	): Promise<{data: unknown[]; searchJobId: number; aggregationJobId: number}> {
52	  const service = getClpQueryService();
53	  const {queryJobDbManager, mongoDb, queryEngine, metadataCollectionName} = service;
54	
55	  const isSearch = "aggregate" !== opts.queryType;
56	
57	  // Build job args matching the Python SearchJobConfig shape
58	  // CLP query scheduler requires non-null datasets; use default dataset when none specified
59	  const datasets = 0 < opts.datasets.length ?
60	    opts.datasets :
61	    [CLP_DEFAULT_DATASET_NAME];
62	
63	  const args = {
64	    begin_timestamp: opts.timeRange.from,
65	    datasets,
66	    end_timestamp: opts.timeRange.to,
67	    ignore_case: opts.ignoreCase,
68	    max_num_results: SEARCH_MAX_NUM_RESULTS,
69	    query_string: opts.queryString,
70	  };
71	
72	  // Submit search job
73	  const searchJobId = await queryJobDbManager.submitJob(
74	    args,
75	    QUERY_JOB_TYPE.SEARCH_OR_AGGREGATION,
76	  );
77	
78	  // Submit aggregation job (always submitted for metadata tracking)
79	  const bucketSize = opts.timeRangeBucketSizeMillis ??
80	    computeTimeRangeBucketSize(opts.timeRange);
81	  const aggregationJobId = await queryJobDbManager.submitJob(
82	    {
83	      ...args,
84	      aggregation_config: {
85	        count_by_time_bucket_size: bucketSize,
86	      },
87	    },
88	    QUERY_JOB_TYPE.SEARCH_OR_AGGREGATION,
89	  );
90	
91	  // Create MongoDB collections for results
92	  await mongoDb.createCollection(searchJobId.toString());
93	  await mongoDb.createCollection(aggregationJobId.toString());
94	
95	  // Insert metadata document
96	  const metadataCollection = mongoDb.collection<SearchResultsMetadataDocument>(metadataCollectionName);
97	  await metadataCollection.insertOne({
98	    _id: searchJobId.toString(),
99	    errorMsg: null,
100	    errorName: null,
101	    lastSignal: SEARCH_SIGNAL.RESP_QUERYING,
102	    queryEngine,
103	  });
104	
105	  // Fire signal update in background — polls MySQL until jobs complete, then updates metadata
106	  updateSearchSignalWhenJobsFinish(
107	    queryJobDbManager,
108	    mongoDb,
109	    metadataCollection,
110	    searchJobId,
111	    aggregationJobId,
112	  ).catch(() => {
113	    // Best effort — errors handled internally
114	  });
115	
116	  // Create indexes for the search results collection
117	  const searchCollection = mongoDb.collection(searchJobId.toString());
118	  await searchCollection.createIndexes([
119	    {key: {timestamp: 1, _id: 1}, name: "timestamp-ascending"},
120	    {key: {timestamp: -1, _id: -1}, name: "timestamp-descending"},
121	  ]);
122	
123	  // Poll loop — read new documents incrementally and emit partial DataFrames
124	  const resultCollectionName = isSearch ?
125	    searchJobId.toString() :
126	    aggregationJobId.toString();
127	  const resultCollection = mongoDb.collection(resultCollectionName);
128	
129	  let lastSeenId: ObjectId | null = null;
130	  let totalDocs = 0;
131	  const allData: unknown[] = [];
132	
133	  try {
134	    // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
135	    while (true) {
136	      // Check for abort
137	      if (callbacks.signal?.aborted) {
138	        await cancelClpQuery(queryJobDbManager, mongoDb, metadataCollection, searchJobId, aggregationJobId);
139	        throw new DOMException("Query cancelled", "AbortError");
140	      }
141	
142	      // Check metadata for job completion
143	      const metadata = await metadataCollection.findOne({
144	        _id: searchJobId.toString(),
145	      });
146	      const isDone = metadata?.lastSignal === SEARCH_SIGNAL.RESP_DONE;
147	      const errorMsg = metadata?.errorMsg;
148	
149	      // Fetch new documents from result collection
150	      const filter: MongoFilter<MongoDoc> = lastSeenId ?
151	        {_id: {$gt: lastSeenId}} :
152	        {};
153	      const newDocs = await resultCollection
154	        .find(filter as unknown as MongoFilter<import("mongodb").Document>)
155	        .sort({_id: 1})
156	        .limit(POLL_BATCH_SIZE)
157	        .toArray();
158	
159	      if (0 < newDocs.length) {
160	        lastSeenId = newDocs[newDocs.length - 1]!._id;
161	        totalDocs += newDocs.length;
162	
163	        // Convert to DataFrame
164	        let frame: unknown;
165	        if (isSearch) {
166	          frame = clpDocumentsToDataFrame(
167	            newDocs as unknown as Parameters<typeof clpDocumentsToDataFrame>[0],
168	            opts.refId,
169	            queryEngine,
170	            SEARCH_MAX_NUM_RESULTS,
171	          );
172	        } else {
173	          frame = clpAggregationToDataFrame(
174	            newDocs as unknown as Parameters<typeof clpAggregationToDataFrame>[0],
175	            opts.refId,
176	          );
177	        }
178	
179	        await callbacks.onPartial({data: [frame]});
180	        allData.push(frame);
181	      }
182	
183	      // If job is done, do one final poll for any remaining docs, then break
184	      if (isDone) {
185	        if (errorMsg) {
186	          throw new Error(errorMsg);
187	        }
188	
189	        // Final poll — drain any remaining documents
190	        let moreDocs = true;
191	        while (moreDocs) {
192	          const remainingFilter: MongoFilter<MongoDoc> = lastSeenId ?
193	            {_id: {$gt: lastSeenId}} :
194	            {};
195	          const remainingDocs = await resultCollection
196	            .find(remainingFilter as unknown as MongoFilter<import("mongodb").Document>)
197	            .sort({_id: 1})
198	            .limit(POLL_BATCH_SIZE)
199	            .toArray();
200	
201	          if (0 === remainingDocs.length) {
202	            moreDocs = false;
203	            break;
204	          }
205	
206	          lastSeenId = remainingDocs[remainingDocs.length - 1]!._id;
207	          totalDocs += remainingDocs.length;
208	
209	          let frame: unknown;
210	          if (isSearch) {
211	            frame = clpDocumentsToDataFrame(
212	              remainingDocs as unknown as Parameters<typeof clpDocumentsToDataFrame>[0],
213	              opts.refId,
214	              queryEngine,
215	              SEARCH_MAX_NUM_RESULTS,
216	            );
217	          } else {
218	            frame = clpAggregationToDataFrame(
219	              remainingDocs as unknown as Parameters<typeof clpAggregationToDataFrame>[0],
220	              opts.refId,
221	            );
222	          }
223	
224	          await callbacks.onPartial({data: [frame]});
225	          allData.push(frame);
226	
227	          if (totalDocs >= SEARCH_MAX_NUM_RESULTS) {
228	            moreDocs = false;
229	          }
230	        }
231	
232	        break;
233	      }
234	
235	      // If we've hit the max results limit, stop polling
236	      if (totalDocs >= SEARCH_MAX_NUM_RESULTS) {
237	        break;
238	      }
239	
240	      // Wait before next poll
241	      await setTimeout(POLL_INTERVAL_MS);
242	    }
243	  } catch (error) {
244	    if (!(error instanceof DOMException && "AbortError" === error.name)) {
245	      // On unexpected error, attempt cleanup
246	      await cancelClpQuery(queryJobDbManager, mongoDb, metadataCollection, searchJobId, aggregationJobId);
247	    }
248	    throw error;
249	  }
250	
251	  return {data: allData, searchJobId, aggregationJobId};
252	}
