254	/**
255	 * Cancels CLP search/aggregation jobs and drops result collections.
256	 *
257	 * @param queryJobDbManager
258	 * @param mongoDb
259	 * @param metadataCollection
260	 * @param searchJobId
261	 * @param aggregationJobId
262	 */
263	export async function cancelClpQuery(
264	  queryJobDbManager: ReturnType<typeof getClpQueryService>["queryJobDbManager"],
265	  mongoDb: Db,
266	  metadataCollection: Collection<SearchResultsMetadataDocument>,
267	  searchJobId: number,
268	  aggregationJobId: number,
269	): Promise<void> {
270	  try {
271	    await queryJobDbManager.cancelJob(searchJobId);
272	  } catch {
273	    // Job may already be complete
274	  }
275	  try {
276	    await queryJobDbManager.cancelJob(aggregationJobId);
277	  } catch {
278	    // Job may already be complete
279	  }
280	
281	  try {
282	    await metadataCollection.updateOne(
283	      {
284	        _id: searchJobId.toString(),
285	        lastSignal: SEARCH_SIGNAL.RESP_QUERYING,
286	      },
287	      {
288	        $set: {
289	          errorMsg: "Query cancelled before it could be completed.",
290	          lastSignal: SEARCH_SIGNAL.RESP_DONE,
291	        },
292	      },
293	    );
294	  } catch {
295	    // Metadata may already be updated
296	  }
297	
298	  try {
299	    await mongoDb.collection(searchJobId.toString()).drop();
300	  } catch {
301	    // Collection may not exist
302	  }
303	  try {
304	    await mongoDb.collection(aggregationJobId.toString()).drop();
305	  } catch {
306	    // Collection may not exist
307	  }
308	}
309	
310	/**
311	 * Polls MySQL until both jobs complete, then updates the metadata document.
312	 * Mirrors the existing updateSearchSignalWhenJobsFinish in search/utils.ts
313	 * but without Fastify logger dependency.
314	 */
315	async function updateSearchSignalWhenJobsFinish(
316	  queryJobDbManager: ReturnType<typeof getClpQueryService>["queryJobDbManager"],
317	  mongoDb: Db,
318	  metadataCollection: Collection<SearchResultsMetadataDocument>,
319	  searchJobId: number,
320	  aggregationJobId: number,
321	): Promise<void> {
322	  let errorMsg: string | null = null;
323	
324	  try {
325	    await queryJobDbManager.awaitJobCompletion(searchJobId);
326	    await queryJobDbManager.awaitJobCompletion(aggregationJobId);
327	  } catch (e: unknown) {
328	    errorMsg = e instanceof Error ?
329	      e.message :
330	      "Error while waiting for job completion";
331	  }
332	
333	  const searchResultCollectionName = searchJobId.toString();
334	  let numResultsInCollection = 0;
335	
336	  try {
337	    numResultsInCollection = await mongoDb.collection(searchResultCollectionName).countDocuments();
338	  } catch {
339	    // Collection may have been dropped
340	    return;
341	  }
342	
343	  await metadataCollection.updateOne(
344	    {
345	      _id: searchJobId.toString(),
346	      lastSignal: SEARCH_SIGNAL.RESP_QUERYING,
347	    },
348	    {
349	      $set: {
350	        lastSignal: SEARCH_SIGNAL.RESP_DONE,
351	        errorMsg,
352	        numTotalResults: Math.min(numResultsInCollection, SEARCH_MAX_NUM_RESULTS),
353	      },
354	    },
355	  );
356	}
