358	/**
359	 * Computes a reasonable time bucket size for aggregation queries.
360	 * Aims for ~40 buckets across the time range.
361	 */
362	function computeTimeRangeBucketSize(range: {from: number; to: number}): number {
363	  const spanMs = range.to - range.from;
364	  return Math.max(1000, Math.floor(spanMs / 40));
365	}
