53	export async function provisionDatasources(
54	  storage: DatasourceStorage,
55	  config?: ProvisioningConfig,
56	): Promise<void> {
57	  const provisioning = config ?? getDefaultProvisioningConfig();
58	  const existing = await storage.list();
59	  const existingUids = new Set(existing.map((ds) => ds.uid));
60	
61	  for (const ds of provisioning.datasources) {
62	    if (existingUids.has(ds.uid ?? "")) continue;
63	
64	    const now = toMySQLDatetime();
65	    const instance: DatasourceInstance = {
66	      id: nanoid(21),
