24	/**
25	 * Presto search API routes.
26	 *
27	 * @param fastify
28	 */
29	// eslint-disable-next-line max-lines-per-function
30	const plugin: FastifyPluginAsyncTypebox = async (fastify) => {
31	    const {Presto, mongo} = fastify;
32	    const mongoDb = mongo.db;
33	
34	    if ("undefined" === typeof Presto) {
35	        // If Presto client is not available, skip the plugin registration.
36	        return;
37	    }
38	
39	    if ("undefined" === typeof mongoDb) {
40	        throw new Error("MongoDB database not found");
41	    }
42	
43	    const searchResultsMetadataCollection = mongoDb.collection<SearchResultsMetadataDocument>(
44	        settings.MongoDbSearchResultsMetadataCollectionName
45	    );
46	
47	    /**
48	     * Submits a search query.
49	     */
50	    fastify.post(
51	        "/query",
52	        {
53	            schema: {
54	                body: PrestoQueryJobCreationSchema as never,
55	                response: {
56	                    [constants.HTTP_STATUS_CREATED]: PrestoQueryJobSchema,
57	                    [constants.HTTP_STATUS_INTERNAL_SERVER_ERROR]: ErrorSchema,
58	                },
59	                tags: ["Presto Search"],
60	            },
61	        },
62	        // eslint-disable-next-line max-lines-per-function
63	        async (request, reply) => {
64	            const {queryString} = request.body as PrestoQueryJobCreation;
65	
66	            let searchJobId: string;
67	            let totalResultsCount = 0;
68	            let storedResultsCount = 0;
69	
70	            try {
71	                // eslint-disable-next-line max-lines-per-function
72	                searchJobId = await new Promise<string>((resolve, reject) => {
73	                    let isResolved = false;
74	                    Presto.client.execute({
75	                        data: (_, data, columns) => {
76	                            totalResultsCount += data.length;
77	
78	                            request.log.info(
79	                                `Received ${data.length} rows from Presto query ` +
80	                                `(total: ${totalResultsCount})`
81	                            );
82	
83	                            if (false === isResolved) {
84	                                request.log.error(
85	                                    "Presto data received before searchJobId was resolved; " +
86	                                    "skipping insert."
87	                                );
88	
89	                                return;
90	                            }
91	
92	                            if (0 === data.length) {
93	                                return;
94	                            }
95	
96	                            if (storedResultsCount < MAX_PRESTO_SEARCH_RESULTS) {
97	                                const remainingSlots =
98	                                    MAX_PRESTO_SEARCH_RESULTS - storedResultsCount;
99	                                const dataToInsert = data.slice(0, remainingSlots);
100	
101	                                if (0 < dataToInsert.length) {
102	                                    storedResultsCount += dataToInsert.length;
103	                                    insertPrestoRowsToMongo(
104	                                        dataToInsert,
105	                                        columns,
106	                                        searchJobId,
107	                                        mongoDb
108	                                    ).catch((err: unknown) => {
109	                                        request.log.error(
110	                                            err,
111	                                            "Failed to insert Presto results into MongoDB"
112	                                        );
113	                                    });
114	                                }
115	                            }
116	
117	                            // Always update metadata with total count
118	                            searchResultsMetadataCollection.updateOne(
119	                                {_id: searchJobId},
120	                                {$set: {numTotalResults: totalResultsCount}}
121	                            ).catch((err: unknown) => {
122	                                request.log.error(
123	                                    err,
124	                                    "Failed to update total results count in metadata"
125	                                );
126	                            });
127	                        },
128	                        error: (error) => {
129	                            request.log.info(error, "Presto search failed");
130	                            if (false === isResolved) {
131	                                isResolved = true;
132	                                reject(new Error("Presto search failed"));
133	                            } else {
134	                                searchResultsMetadataCollection.updateOne(
135	                                    {_id: searchJobId},
136	                                    {
137	                                        $set: {
138	                                            errorMsg: error.message,
139	                                            errorName: ("errorName" in error) ?
140	                                                error.errorName :
141	                                                null,
142	                                            lastSignal: PRESTO_SEARCH_SIGNAL.FAILED,
143	                                        },
144	                                    }
145	                                ).catch((err: unknown) => {
146	                                    request.log.error(
147	                                        err,
148	                                        "Failed to update Presto error metadata"
149	                                    );
150	                                });
151	                            }
152	                        },
153	                        query: queryString,
154	                        state: (_, queryId, stats) => {
155	                            request.log.info({
156	                                searchJobId: queryId,
157	                                state: stats.state,
158	                            }, "Presto search state updated");
159	
160	                            // Insert metadata and resolve queryId on first call
161	                            if (false === isResolved) {
162	                                searchResultsMetadataCollection.insertOne({
163	                                    _id: queryId,
164	                                    errorMsg: null,
165	                                    errorName: null,
166	                                    lastSignal: PRESTO_SEARCH_SIGNAL.QUERYING,
167	                                    queryEngine: CLP_QUERY_ENGINES.PRESTO,
168	                                }).catch((err: unknown) => {
169	                                    request.log.error(err, "Failed to insert Presto metadata");
170	                                });
171	                                isResolved = true;
172	                                resolve(queryId);
173	                            }
174	                        },
175	                        success: () => {
176	                            if (false === isResolved) {
177	                                request.log.error(
178	                                    "Presto query finished before searchJobId was resolved; "
179	                                );
180	
181	                                return;
182	                            }
183	                            searchResultsMetadataCollection.updateOne(
184	                                {_id: searchJobId},
185	                                {$set: {lastSignal: PRESTO_SEARCH_SIGNAL.DONE}}
186	                            ).catch((err: unknown) => {
187	                                request.log.error(err, "Failed to update Presto metadata");
188	                            });
189	
190	                            request.log.info("Presto search succeeded");
191	                        },
192	                        timeout: null,
193	                    });
194	                });
195	            } catch (error) {
196	                request.log.error(error, "Failed to submit Presto query");
197	                throw error;
198	            }
199	
200	            await mongoDb.createCollection(searchJobId);
201	
202	            reply.code(constants.HTTP_STATUS_CREATED);
203	
204	            return {searchJobId};
205	        }
206	    );
207	
208	    fastify.post(
209	        "/cancel",
210	        {
211	            schema: {
212	                body: PrestoQueryJobSchema as never,
213	                response: {
214	                    [constants.HTTP_STATUS_NO_CONTENT]: Type.Null(),
215	                    [constants.HTTP_STATUS_INTERNAL_SERVER_ERROR]: ErrorSchema,
216	                },
217	                tags: ["Presto Search"],
218	            },
219	        },
220	        async (request, reply) => {
221	            const {searchJobId} = request.body as PrestoQueryJob;
222	            await new Promise<void>((resolve, reject) => {
223	                Presto.client.kill(searchJobId, (error) => {
224	                    if (null !== error) {
225	                        reject(new Error("Failed to kill the Presto query job.", {cause: error}));
226	                    }
227	                    resolve();
228	                });
229	            });
230	            request.log.info({searchJobId}, "Presto search cancelled");
231	            reply.code(constants.HTTP_STATUS_NO_CONTENT);
232	
233	            return null;
234	        }
235	    );
236	
237	    fastify.delete(
238	        "/results",
239	        {
240	            schema: {
241	                body: PrestoQueryJobSchema as never,
242	                response: {
243	                    [constants.HTTP_STATUS_NO_CONTENT]: Type.Null(),
244	                    [constants.HTTP_STATUS_INTERNAL_SERVER_ERROR]: ErrorSchema,
245	                },
246	                tags: ["Presto Search"],
247	            },
248	        },
249	        async (request, reply) => {
250	            const {searchJobId} = request.body as PrestoQueryJob;
251	
252	            request.log.info({
253	                searchJobId,
254	            }, "api/presto-search/results args");
255	
256	            await mongoDb.collection(searchJobId).drop();
257	
258	            reply.code(constants.HTTP_STATUS_NO_CONTENT);
259	
260	            return null;
261	        }
262	    );
263	};
