1	import type {FastifyInstance, FastifyPluginOptions, FastifyRequest, FastifyReply} from "fastify";
2	import {CLP_QUERY_ENGINES} from "@webui/common/config";
3	import fp from "fastify-plugin";
4	import mysql from "mysql2/promise";
5	import {honoApp} from "../../hono-app.js";
6	import {setDashboardStorage} from "../../hono-routes/dashboards.js";
7	import {MySQLDashboardStorage, DASHBOARD_MIGRATION} from "../../storage/dashboard-storage.js";
8	import {setClpQueryService} from "../../hono-routes/clp-query-service.js";
9	import {setDatasourceStorage} from "../../hono-routes/datasource.js";
10	import {MySQLDatasourceStorage, DATASOURCE_MIGRATION} from "../../storage/datasource-storage.js";
11	import {provisionDatasources} from "../../storage/provisioning.js";
12	import settings from "../../../settings.json" with {type: "json"};
13	
14	/**
15	 * Delegates /api/dashboards/* and /api/datasource/* requests to the Hono app.
16	 * Same-port coexistence: Fastify is the primary server, Hono handles dashboard routes.
17	 * Also wires MySQL storage for dashboard/datasource persistence and runs migrations.
18	 */
19	async function honoDelegation(fastify: FastifyInstance, _opts: FastifyPluginOptions) {
20	  // Wire MySQL storage for persistence
21	  const {CLP_DB_USER, CLP_DB_PASS} = fastify.config;
22	  const mysqlConfig = {
23	    host: settings.SqlDbHost,
24	    port: settings.SqlDbPort,
25	    user: CLP_DB_USER,
26	    password: CLP_DB_PASS,
27	    database: settings.SqlDbName,
28	  };
29	
30	  const getMySQLConnection = () => mysql.createConnection(mysqlConfig);
31	
32	  // Run migrations
33	  const conn = await mysql.createConnection(mysqlConfig);
34	  try {
35	    await conn.query(DASHBOARD_MIGRATION);
36	    await conn.query(DATASOURCE_MIGRATION);
37	  } finally {
38	    await conn.end();
39	  }
40	
41	  // Set MySQL storage backends
42	  setDashboardStorage(new MySQLDashboardStorage(getMySQLConnection));
43	  setDatasourceStorage(new MySQLDatasourceStorage(getMySQLConnection));
44	
45	  // Provision default datasources on first startup
46	  await provisionDatasources(new MySQLDatasourceStorage(getMySQLConnection));
47	
48	  // Wire CLP query service (QueryJobDbManager + MongoDB) for dashboard datasource routes
49	  const mongoDb = fastify.mongo.db;
50	  if ("undefined" === typeof mongoDb) {
51	    throw new Error("MongoDB database not found");
52	  }
53	  setClpQueryService({
54	    queryJobDbManager: fastify.QueryJobDbManager,
55	    mongoDb,
56	    queryEngine: settings.ClpQueryEngine as CLP_QUERY_ENGINES,
57	    metadataCollectionName: settings.MongoDbSearchResultsMetadataCollectionName,
58	  });
59	
60	  const honoFetch = honoApp.fetch;
61	
62	  const delegateToHono = async (request: FastifyRequest, reply: FastifyReply) => {
63	    let urlPath = request.url;
64	    // Normalize trailing slash so Hono matches root routes on mounted sub-paths
65	    if (urlPath.endsWith("/") && urlPath.split("/").filter(Boolean).length > 0) {
66	      const basePath = urlPath.replace(/\/+$/, "");
67	      if (basePath === "/api/dashboards" || basePath === "/api/datasource") {
68	        urlPath = basePath;
69	      }
70	    }
71	    const url = `${request.protocol}://${request.hostname}${urlPath}`;
72	    const init: RequestInit = {
73	      method: request.method,
74	      headers: Object.entries(request.headers).filter(([, v]) => v !== undefined) as [string, string][],
75	    };
76	    if (request.body) {
77	      init.body = JSON.stringify(request.body);
78	    }
79	    const webReq = new Request(url, init);
80	    const res = await honoFetch(webReq);
81	
82	    // Check if the response is SSE (streaming)
83	    const contentType = res.headers.get("content-type") ?? "";
84	    if (contentType.includes("text/event-stream")) {
85	      // Stream SSE responses properly through Fastify
86	      reply.raw.writeHead(res.status, Object.fromEntries(res.headers.entries()));
87	      const reader = res.body?.getReader();
88	      if (reader) {
89	        try {
90	          // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
91	          while (true) {
92	            const {done, value} = await reader.read();
93	            if (done) break;
94	            reply.raw.write(value);
95	          }
96	        } finally {
97	          reply.raw.end();
98	        }
99	      }
100	
101	      return;
102	    }
103	
104	    reply.code(res.status);
105	    for (const [key, value] of res.headers.entries()) {
106	      reply.header(key, value);
107	    }
108	    return res.text();
109	  };
110	
111	  fastify.all("/api/dashboards", delegateToHono);
112	  fastify.all("/api/dashboards/*", delegateToHono);
113	  fastify.all("/api/datasource", delegateToHono);
114	  fastify.all("/api/datasource/*", delegateToHono);
115	}
116	
117	export default fp(honoDelegation, {name: "hono-delegation"});
